import java.lang.Math;

public class Solution {
    public static long solve(long n, long m, long k) {
        long required_k = Math.max(n / 2, m / 2);
        if (k >= required_k) {
            return 1;
        } else {
            long step = 2 * k + 1;
            long rows = (n + step - 1) / step;
            long cols = (m + step - 1) / step;
            return rows * cols;
        }
    }
}
